    onFail: (id: string) => void;
    onStartQuest: (q: Quest) => void;
    onAddQuest: (name: string, difficulty: Difficulty, type: 'repetitive' | 'one-time', attributes: Attribute[], description: string, rounds: number, roundDuration: number, intervalDuration: number) => void;
}> = ({ quests, onComplete, onDelete, onFail, onStartQuest, onAddQuest }) => {
