                let color = 'border-blue-500 text-blue-200';
                let bg = 'bg-slate-900/95 shadow-[0_0_20px_rgba(56,189,248,0.3)]';

                if (n.type === 'danger') {
                  color = 'border-red-600 text-red-200';
                  bg = 'bg-red-950/90 shadow-[0_0_20px_rgba(220,38,38,0.4)]';
