                            <span>{n.label}</span>
                        </button>
                    ))}
                </nav>
                <footer className="mt-auto pt-10 text-[8px] font-orbitron text-blue-500/40 tracking-widest uppercase">
                    &copy; 2025 R.L.L OS // IMMUTABLE
                </footer>
            </aside>

            <div className="lg:hidden fixed top-0 left-0 right-0 bg-slate-950/80 backdrop-blur-md border-b border-blue-500/20 z-[100] p-4 flex justify-between items-center">
                <h1 className="font-orbitron font-black text-xl text-blue-400">R.L.L</h1>
                <button onClick={() => setPage('menu')} className="p-2 bg-blue-600 rounded-sm"><MenuIcon /></button>
            </div>

            <main className="flex-grow overflow-y-auto custom-scrollbar pt-20 lg:pt-0">
                <div className="max-w-6xl mx-auto p-6 lg:p-16">
                    {render()}
