            </main>

            <ConfirmationModal isOpen={!!confirm} title={confirm?.title || ''} message={confirm?.message || ''} onConfirm={confirm?.onConfirm || (() => {})} onCancel={() => setConfirm(null)} isDangerous={confirm?.isDangerous} />
        </div>
    );
};

