const getAttributeGradeData = (val: number) => {
  if (val <= 100) return { grade: 'E', min: 0, max: 100, color: 'from-gray-600 to-gray-400', glow: 'rgba(156, 163, 175, 0.4)', text: 'text-gray-400' };
  if (val <= 250) return { grade: 'D', min: 101, max: 250, color: 'from-green-600 to-green-400', glow: 'rgba(74, 222, 128, 0.4)', text: 'text-green-400' };
  if (val <= 500) return { grade: 'C', min: 251, max: 500, color: 'from-orange-600 to-orange-400', glow: 'rgba(251, 146, 60, 0.4)', text: 'text-orange-400' };
  if (val <= 1000) return { grade: 'B', min: 501, max: 1000, color: 'from-indigo-600 to-indigo-400', glow: 'rgba(129, 140, 248, 0.4)', text: 'text-indigo-400' };
  if (val <= 1500) return { grade: 'A', min: 1001, max: 1500, color: 'from-purple-600 to-purple-400', glow: 'rgba(192, 132, 252, 0.4)', text: 'text-purple-400' };
  if (val <= 3000) return { grade: 'S', min: 1501, max: 3000, color: 'from-yellow-600 to-yellow-400', glow: 'rgba(250, 204, 21, 0.4)', text: 'text-yellow-400' };
  return { grade: 'S+', min: 3001, max: 3001, color: 'from-red-600 to-red-400', glow: 'rgba(239, 68, 68, 0.6)', text: 'text-red-500', isMax: true };
};

export const PlayerStats: React.FC<PlayerStatsProps> = ({ player, onRename }) => {
