export enum Difficulty {
  E = 'E',
  D = 'D',
  C = 'C',
  B = 'B',
  A = 'A',
  S = 'S',
  S_PLUS = 'S+',
  X = 'X',
}

export enum Rank {
  E = 'E',
  D = 'D',
  C = 'C',
  B = 'B',
  A = 'A',
  S = 'S',
}

export enum Attribute {
  Intellect = 'Intellect',
  Strength = 'Strength',
  Agility = 'Agility',
  Endurance = 'Endurance',
  Perception = 'Perception',
}

export interface PlayerAttributes {
  [Attribute.Intellect]: number;
  [Attribute.Strength]: number;
  [Attribute.Agility]: number;
  [Attribute.Endurance]: number;
  [Attribute.Perception]: number;
}

export interface Quest {
  id: string;
  name: string;
  description?: string;
  difficulty: Difficulty;
  type: 'repetitive' | 'one-time';
  attributes: Attribute[];
  rounds?: number;
  roundDuration?: number; // in seconds
  intervalDuration?: number; // in seconds
  isSystemQuest?: boolean;
  failurePenalty?: {
    xp: number;
  };
}

export interface CompletedQuest extends Quest {
  completedAt: string;
  completionId: string;
}

export interface SkillPrerequisite {
  skillId: string;
  requiredStars: number;
}

export interface SkillFolder {
  id: string;
  name: string;
  category: string;
  icon?: string;
}

export interface SkillCategory {
  name: string;
  icon: string;
}

export interface Skill {
  id: string;
  name: string;
  description?: string;
  guide?: string;
  grade: Difficulty;
  originalGrade: Difficulty; // Used for progression rules
  stars: number;
  starProgress: number;
  status: 'locked' | 'unlocked';
  unlockProgress: number;
  category?: string;
  folderId?: string;
  prerequisites?: SkillPrerequisite[];
  masteryLevel?: number; // 0: White, 1: Blue, 2: Purple, 3: Gold, 4: Red
  dailyTraining?: { date: string; count: number }; // Added to track daily limit
}

export interface Player {
  name: string;
  level: number;
  xp: number;
  rank: Rank;
  attributes: PlayerAttributes;
  shopCoins: number;
  unlockedTitles: string[];
  equippedTitle: string | null;
}

export interface DungeonFloor {
    id: string;
    name: string;
    tasks: DungeonTask[];
}

export interface DungeonTask {
    id: string;
    description: string;
    attribute?: Attribute;
    page: {
        title: string;
        narrative: string;
    };
}

export interface Dungeon {
    id:string;
    name: string;
    grade: Difficulty;
    description: string;
    type?: 'standard' | 'temptation';
    timeLimit?: number;
    floors: DungeonFloor[];
    rewards?: {
        xp: number;
        coins?: number;
    };
    failurePenalty?: {
        xp: number;
    };
}

export interface ActiveDungeonState {
    id: string;
    dungeonId: string;
    startedAt: number;
    currentFloorIndex: number;
    currentTaskIndex: number;
    taskStatus: Record<string, boolean>;
}

export interface DungeonCooldown {
    date: string;
    status: 'cleared' | 'failed';
}

export interface DungeonHistoryEntry {
    id: string;
    name: string;
    grade: Difficulty;
    completedAt: number;
    status: 'cleared' | 'failed';
}

export type EquipmentSlot = 'helmet' | 'armor' | 'gloves' | 'boots' | 'gear';

export interface ShopItem {
  id: string;
  name: string;
  type: 'Gear' | 'Potion';
  slot?: EquipmentSlot;
  rank: Difficulty;
  bonusXp?: number;
  effectDescription: string;
  cost: number;
  // Enhancement stats
  enhancementLevel?: number; // 0-5
  stars?: number; 
  unlockedTraits?: number[]; // list of XP bonuses from stars
}

export interface MaterialItem {
    id: string;
    name: string;
    count: number;
    rank: Difficulty;
}

export interface Inventory {
    equipment: {
        helmet: ShopItem | null;
        armor: ShopItem | null;
        gloves: ShopItem | null;
        boots: ShopItem | null;
        gear: ShopItem | null;
    };
    storage: ShopItem[];
    materials: MaterialItem[];
}

export interface Achievement {
    id: string;
    name: string;
    description: string;
    rank: Difficulty;
    isUnlocked: boolean;
    unlockDate: number | null;
    progress: number;
    goal: number;
    nextTierId?: string; 
    titleReward?: string;
    rewardCoins: number;
    type: 'COMPLETE_QUEST' | 'CLEAR_DUNGEON' | 'TRAIN_SKILL' | 'MASTER_SKILL' | 'REACH_LEVEL' | 'OWN_GEAR' | 'ADVANCE_GEAR' | 'ADVANCE_SKILL';
    meta?: {
        difficulty?: Difficulty;
        grade?: Difficulty;
    };
}

export interface Title {
    id: string;
    name: string;
    rank: Difficulty;
}

export interface PlannerItem {
  id: string;
  text: string;
  completed: boolean;
}

export type DayOfWeek = 'monday' | 'tuesday' | 'wednesday' | 'thursday' | 'friday' | 'saturday' | 'sunday';

export type WeeklyPlan = Record<DayOfWeek, PlannerItem[]>;

export interface SystemNotification {
    id: string;
    title: string;
    message: string;
    type: 'success' | 'danger' | 'info' | 'warning' | 'achievement' | 'level_up';
}

export type Page = 'menu' | 'status' | 'stats' | 'quests' | 'add-quest' | 'history' | 'skills' | 'add-skill' | 'dungeons' | 'task-list' | 'achievements' | 'shop' | 'inventory' | 'workshop' | 'codex' | 'report';

export type PlayerDataEvent =
    | { type: 'xp_gain'; amount: number; source: string; }
    | { type: 'stats_gain'; gains: { attribute: Attribute; amount: number }[]; }
    | { type: 'achievement_unlocked'; achievement: Achievement; }
    | { type: 'dungeon_cleared'; name: string; rewards: { xp: number; coins?: number }; drops?: string[]; }
    | { type: 'skill_ascended'; skillName: string; newGrade: Difficulty; newMasteryLevel: number; }
    | { type: 'quest_started'; name: string; difficulty: Difficulty; }
    | { type: 'quest_attempted'; name: string; difficulty: Difficulty; }
    | { type: 'quest_cleared'; name: string; difficulty: Difficulty; rewards: { xp: number; coins?: number }; }
    | { type: 'dungeon_started'; name: string; grade: Difficulty; }
    | { type: 'level_up'; level: number; rank: Rank; };

export interface PlayerDataState {
  dataVersion?: number;
  player: Player;
  quests: Quest[];
  completedQuests: CompletedQuest[];
  skills: Skill[];
  skillFolders: SkillFolder[];
  categories: SkillCategory[];
  activeDungeon: ActiveDungeonState | null;
  dungeonCooldowns: Record<string, DungeonCooldown>; 
  dungeonHistory: DungeonHistoryEntry[];
  achievements: Record<string, Achievement>;
  inventory: Inventory;
  weeklyPlan: WeeklyPlan;
  events: PlayerDataEvent[];
  notifications: SystemNotification[];
}

// Added missing Saga and Spiritual Realm types
export interface Saga {
    id: string;
    name: string;
    grade: Difficulty;
    description: string;
    endDate: number;
    maxDisciplineFailures: number;
}

export interface ActiveSaga {
    sagaId: string;
    disciplineFailures: number;
}

export interface SpiritualTask {
    id: string;
    name: string;
    type: 'mandatory' | 'obligatory';
    reward: {
        xp: number;
        deen: number;
    };
}

export interface SpiritualRealmState {
    deen: number;
    tasks: SpiritualTask[];
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { Player, Quest, Difficulty, PlayerDataState, CompletedQuest, Skill, Attribute, SkillPrerequisite, SkillFolder, SkillCategory, ActiveDungeonState, DungeonCooldown, DungeonHistoryEntry, Inventory, Achievement, ShopItem, EquipmentSlot, PlayerDataEvent, WeeklyPlan, DayOfWeek, PlannerItem, MaterialItem, SystemNotification } from '../types';
import { Rank, Difficulty as DifficultyEnum } from '../types';
import { XP_PER_DIFFICULTY, getXpToNextLevel, getRankForLevel, TRAINING_PER_HALF_STAR, SKILL_UNLOCK_REQUIREMENTS, XP_FOR_SKILL_UNLOCK, STAT_POINTS_PER_DIFFICULTY, DUNGEONS, SYSTEM_QUESTS, XP_FOR_SKILL_ASCENSION, QUEST_COIN_REWARDS, ACHIEVEMENTS_DATA, MATERIALS, ADVANCEMENT_TRAITS, X_RANK_PENALTY_OVERRIDE, DAILY_XP_GOAL } from '../constants';

const DATA_VERSION = 11;
const Berserker_GEAR_IDS = ['armor_berserker'];

const getScalingXpBonus = (itemId: string, sourceRank: Difficulty): number => {
    if (itemId.includes('_rogue')) {
        if ([DifficultyEnum.E, DifficultyEnum.D].includes(sourceRank)) return 0;
        return 1;
    }
    if (itemId.includes('_iron')) {
        if ([DifficultyEnum.E, DifficultyEnum.D].includes(sourceRank)) return 0;
        return 2;
    }
    if (itemId.includes('_shadow')) {
        if ([DifficultyEnum.E, DifficultyEnum.D].includes(sourceRank)) return 0;
        if ([DifficultyEnum.C].includes(sourceRank)) return 2;
        if ([DifficultyEnum.B].includes(sourceRank)) return 3;
        return 5;
    }
    if (itemId.includes('_light')) {
        switch (sourceRank) {
            case DifficultyEnum.E:
            case DifficultyEnum.D: return 0;
            case DifficultyEnum.C: return 3;
            case DifficultyEnum.B: return 5;
            case DifficultyEnum.A: return 8;
            case DifficultyEnum.S: return 12;
            case DifficultyEnum.S_PLUS: return 25;
            default: return 0;
        }
    }
    if (itemId === 'gear_dragon_slayer') {
        switch (sourceRank) {
            case DifficultyEnum.E: return 1;
            case DifficultyEnum.D: return 2;
            case DifficultyEnum.C: return 3;
            case DifficultyEnum.B: return 5;
            case DifficultyEnum.A: return 15;
            case DifficultyEnum.S: return 30;
            case DifficultyEnum.S_PLUS: return 50;
            default: return 0;
        }
    }
    if (Berserker_GEAR_IDS.includes(itemId)) {
        switch (sourceRank) {
            case DifficultyEnum.E: return 2;
            case DifficultyEnum.D: return 3;
            case DifficultyEnum.C: return 5;
            case DifficultyEnum.B: return 10;
            case DifficultyEnum.A: return 25;
            case DifficultyEnum.S: return 50;
            case DifficultyEnum.S_PLUS: return 100;
            default: return 0;
        }
    }
    return 0;
};

const DEFAULT_STATE: PlayerDataState = {
    dataVersion: DATA_VERSION,
    player: { name: 'Hunter', level: 1, xp: 0, rank: Rank.E, attributes: { [Attribute.Intellect]: 1, [Attribute.Strength]: 1, [Attribute.Agility]: 1, [Attribute.Endurance]: 1, [Attribute.Perception]: 1 }, shopCoins: 0, unlockedTitles: [], equippedTitle: null },
    quests: [...SYSTEM_QUESTS], completedQuests: [], skills: [], skillFolders: [], categories: [], activeDungeon: null, dungeonCooldowns: {}, dungeonHistory: [], achievements: { ...ACHIEVEMENTS_DATA },
    inventory: { equipment: { helmet: null, armor: null, gloves: null, boots: null, gear: null }, storage: [], materials: [] },
    weeklyPlan: { monday: [], tuesday: [], wednesday: [], thursday: [], friday: [], saturday: [], sunday: [] },
    events: [],
    notifications: []
};

const getInitialState = (): PlayerDataState => {
    try {
        const saved = localStorage.getItem('playerData');
        if (saved) {
            const parsed = JSON.parse(saved);
            const sanitizedInventory: Inventory = {
                equipment: { ...DEFAULT_STATE.inventory.equipment, ...(parsed.inventory?.equipment || {}) },
                storage: Array.isArray(parsed.inventory?.storage) ? parsed.inventory.storage : [],
                materials: Array.isArray(parsed.inventory?.materials) ? parsed.inventory.materials : []
            };
            return { 
                ...DEFAULT_STATE, 
                ...parsed, 
                skills: Array.isArray(parsed.skills) ? parsed.skills.map((s: any) => ({ ...s, originalGrade: s.originalGrade || s.grade })) : [],
                quests: Array.isArray(parsed.quests) ? parsed.quests : DEFAULT_STATE.quests,
                inventory: sanitizedInventory, 
                achievements: { ...ACHIEVEMENTS_DATA, ...(parsed.achievements || {}) }, 
                dataVersion: DATA_VERSION, 
                notifications: [] 
            };
        }
    } catch (e) { console.error("Critical: Failed to restore system state.", e); }
    return DEFAULT_STATE;
};

export const usePlayerData = () => {
    const [state, setState] = useState<PlayerDataState>(getInitialState);

    useEffect(() => {
        localStorage.setItem('playerData', JSON.stringify({ ...state, events: [], notifications: [] }));
    }, [state]);

    const addNotification = useCallback((title: string, message: string, type: SystemNotification['type'] = 'info') => {
        const id = `notif-${Date.now()}-${Math.random()}`;

        setState(s => ({
            ...s,
            notifications: [...s.notifications, { id, title, message, type }]
        }));

        // Automatically remove the notification after the CSS animation duration (4.5s)
        setTimeout(() => {
            setState(s => ({
                ...s,
                notifications: s.notifications.filter(n => n.id !== id)
            }));
        }, 4500);

        if (type === 'danger') {
            const flash = document.createElement('div');
            flash.className = 'fixed inset-0 bg-red-900/40 pointer-events-none z-[400] animate-[pulse_0.4s_ease-out_forwards]';
            document.body.appendChild(flash);
            setTimeout(() => flash.remove(), 400);
        }
    }, []);

    const addEvent = useCallback((event: PlayerDataEvent) => setState(s => ({ ...s, events: [...s.events, event] })), []);
    const clearEvents = useCallback(() => setState(s => ({ ...s, events: [] })), []);

    const checkAchievements = useCallback((type: Achievement['type'], meta?: any, amount: number = 1) => {
        setState(prevState => {
            const achievements = { ...prevState.achievements };
            let stateChanged = false;
            let totalCoinBonus = 0;
            Object.keys(achievements).forEach(key => {
                const originalAch = achievements[key];
                if (originalAch.isUnlocked || originalAch.type !== type) return;
                if (originalAch.meta) {
                    if (originalAch.type === 'COMPLETE_QUEST' && originalAch.meta.difficulty && originalAch.meta.difficulty !== meta?.difficulty) return;
                    if (originalAch.type === 'CLEAR_DUNGEON' && originalAch.meta.grade && originalAch.meta.grade !== meta?.grade) return;
                    if (originalAch.type === 'OWN_GEAR' && originalAch.meta.grade && originalAch.meta.grade !== meta?.grade) return;
                }
                let newProgress = originalAch.progress;
                if (originalAch.type === 'OWN_GEAR') newProgress = meta?.count ?? originalAch.progress;
                else if (originalAch.type === 'REACH_LEVEL') newProgress = Math.max(originalAch.progress, meta?.level ?? 0);
                else newProgress += amount;

                if (newProgress !== originalAch.progress) {
                    stateChanged = true;
                    const updatedAch = { ...originalAch, progress: newProgress };
                    if (updatedAch.progress >= updatedAch.goal) {
                        updatedAch.progress = updatedAch.goal;
                        updatedAch.isUnlocked = true;
                        updatedAch.unlockDate = Date.now();
                        totalCoinBonus += updatedAch.rewardCoins;
                        // Trigger achievement unlock immediately (Milestone Group)
                        setTimeout(() => addNotification('ACHIEVEMENT UNLOCKED', `${updatedAch.name} accomplished!`, 'achievement'), 0);
                    }
                    achievements[key] = updatedAch;
                }
            });
            if (!stateChanged) return prevState;
            return { ...prevState, achievements, player: { ...prevState.player, shopCoins: prevState.player.shopCoins + totalCoinBonus } };
        });
    }, [addNotification]);

    const gainXp = useCallback((amount: number, source: string, manualRank?: Difficulty) => {
        setState(prevState => {
            const sourceRank = manualRank || (Array.isArray(prevState.quests) ? prevState.quests.find(q => q.name === source)?.difficulty : undefined) || DUNGEONS.find(d => `Cleared ${d.name}` === source || `Failed ${d.name}` === source)?.grade;
            let totalBonus = 0;
            const equipped = Object.values(prevState.inventory.equipment).filter(Boolean) as ShopItem[];
            if (sourceRank && amount > 0) {
                equipped.forEach(item => {
                    totalBonus += getScalingXpBonus(item.id, sourceRank);
                    if (item.unlockedTraits && item.unlockedTraits.length > 0 && [DifficultyEnum.B, DifficultyEnum.A, DifficultyEnum.S, DifficultyEnum.S_PLUS, DifficultyEnum.X].includes(sourceRank)) {
                        totalBonus += item.unlockedTraits.reduce((a, b) => a + b, 0);
                    }
                });
            }
            let finalAmount = amount + (amount > 0 ? totalBonus : 0);
            const shadowItemCount = equipped.filter(i => Berserker_GEAR_IDS.includes(i.id)).length;

            if (finalAmount < 0 && shadowItemCount > 0) finalAmount *= (1 + shadowItemCount);
            if (sourceRank === DifficultyEnum.X && shadowItemCount > 0 && amount < 0) finalAmount = -X_RANK_PENALTY_OVERRIDE;

            let newXp = (prevState.player?.xp || 0) + finalAmount;
            let newLevel = prevState.player?.level || 1;
            const oldRank = prevState.player?.rank || Rank.E;

            while (newXp >= getXpToNextLevel(newLevel)) {
                newXp -= getXpToNextLevel(newLevel);
                newLevel++;
                const currentNewLevel = newLevel;
                setTimeout(() => checkAchievements('REACH_LEVEL', { level: currentNewLevel }, 0), 0);
            }
            while (newXp < 0 && newLevel > 1) {
                newLevel--;
                newXp += getXpToNextLevel(newLevel);
            }
            if (newLevel === 1 && newXp < 0) newXp = 0;
            const newRank = getRankForLevel(newLevel);

            // All Milestone/Reward notifications triggered here should pop up simultaneously
            if (finalAmount !== 0) setTimeout(() => addNotification(finalAmount > 0 ? 'XP ACQUIRED' : 'SYSTEM PENALTY', `${finalAmount > 0 ? '+' : ''}${Math.round(finalAmount)} XP from ${source}`, finalAmount > 0 ? 'info' : 'danger'), 0);
            if (newLevel > prevState.player.level) setTimeout(() => addNotification('LEVEL UP', `You have reached Level ${newLevel}!`, 'level_up'), 0);
            if (newRank !== oldRank) setTimeout(() => addNotification(newLevel > prevState.player.level ? 'RANK PROMOTION' : 'RANK DEMOTION', `System has updated your ranking to [${newRank}].`, newLevel > prevState.player.level ? 'achievement' : 'danger'), 0);

            return { ...prevState, player: { ...prevState.player, xp: Math.max(0, newXp), level: newLevel, rank: newRank }, events: [...prevState.events, { type: 'xp_gain', amount: finalAmount, source }] };
        });
    }, [addNotification, checkAchievements]);

    useEffect(() => {
        const checkDailyPenalties = () => {
            const todayStr = new Date().toISOString().split('T')[0];
            const lookbackDays = 14;
            let penaltyApplied = false;
            let appliedDates: string[] = [];

            setState(currentState => {
                const newCompletedQuests = [...currentState.completedQuests];
                let currentXp = currentState.player.xp;
                let currentLevel = currentState.player.level;

                for (let i = 1; i <= lookbackDays; i++) {
                    const checkDate = new Date();
                    checkDate.setDate(checkDate.getDate() - i);
                    const checkDateStr = checkDate.toISOString().split('T')[0];
                    const dailyXp = currentState.completedQuests
                        .filter(q => q.completedAt.startsWith(checkDateStr) && !q.isSystemQuest)
                        .reduce((sum, q) => sum + (XP_PER_DIFFICULTY[q.difficulty] || 0), 0) +
                        currentState.dungeonHistory
                        .filter(d => new Date(d.completedAt).toISOString().split('T')[0] === checkDateStr && d.status === 'cleared')
                        .reduce((sum, d) => sum + (DUNGEONS.find(dd => dd.id === d.id)?.rewards?.xp || 0), 0);

                    const alreadyPenalized = currentState.completedQuests.some(q => q.id === 'sys_x_01' && q.completedAt.startsWith(checkDateStr));

                    if (dailyXp < DAILY_XP_GOAL && !alreadyPenalized) {
                        const slothQuest = SYSTEM_QUESTS.find(q => q.id === 'sys_x_01') || currentState.quests.find(q => q.id === 'sys_x_01');
                        if (slothQuest) {
                            penaltyApplied = true;
                            appliedDates.push(checkDateStr);
                            const penaltyRecord: CompletedQuest = { ...slothQuest, completedAt: `${checkDateStr}T23:59:59Z`, completionId: `penalty-${checkDateStr}-${Date.now()}` };
                            newCompletedQuests.push(penaltyRecord);
                            let amount = - (slothQuest.failurePenalty?.xp || 250);
                            const equipped = Object.values(currentState.inventory.equipment).filter(Boolean) as ShopItem[];
                            const shadowItemCount = equipped.filter(i => Berserker_GEAR_IDS.includes(i.id)).length;
                            if (amount < 0 && shadowItemCount > 0) amount *= (1 + shadowItemCount);
                            if (shadowItemCount > 0) amount = -X_RANK_PENALTY_OVERRIDE;
                            currentXp += amount;
                        }
                    }
                }
                if (!penaltyApplied) return currentState;
                while (currentXp >= getXpToNextLevel(currentLevel)) { currentXp -= getXpToNextLevel(currentLevel); currentLevel++; }
                while (currentXp < 0 && currentLevel > 1) { currentLevel--; currentXp += getXpToNextLevel(currentLevel); }
                if (currentLevel === 1 && currentXp < 0) currentXp = 0;
                setTimeout(() => { appliedDates.forEach(d => addNotification('SLOTH PENALTY', `Discipline failure detected on ${d}.`, 'danger')); }, 0);
                return { ...currentState, completedQuests: newCompletedQuests, player: { ...currentState.player, xp: currentXp, level: currentLevel, rank: getRankForLevel(currentLevel) } };
            });
        };
        const timeout = setTimeout(checkDailyPenalties, 1500); 
        return () => clearTimeout(timeout);
    }, [addNotification, state.completedQuests.length]);

    const checkOwnershipAchievements = useCallback((inventory: Inventory) => {
        const allGear = [...inventory.storage, ...Object.values(inventory.equipment)].filter(i => i && i.type === 'Gear') as ShopItem[];
        [DifficultyEnum.S, DifficultyEnum.S_PLUS, DifficultyEnum.X].forEach(grade => {
            const count = allGear.filter(g => g.rank === grade).length;
            if (count > 0) checkAchievements('OWN_GEAR', { grade, count }, 0);
        });
    }, [checkAchievements]);

    const completeQuest = useCallback((id: string) => {
        setState(prevState => {
            const q = prevState.quests.find(x => x.id === id);
            if (!q) return prevState;
            const completionRecord: CompletedQuest = { ...q, completedAt: new Date().toISOString(), completionId: `c-${Date.now()}-${Math.random().toString(36).substr(2, 9)}` };
            const statPoints = STAT_POINTS_PER_DIFFICULTY[q.difficulty] || 0;
            const newAttributes = { ...prevState.player.attributes };

            // Trigger notifications for Reward group simultaneously
            if (q.attributes && q.attributes.length > 0 && statPoints > 0) {
                q.attributes.forEach((attr) => {
                    newAttributes[attr] = (newAttributes[attr] || 0) + statPoints;
                    setTimeout(() => addNotification('STAT INCREASE', `${attr.toUpperCase()} +${statPoints}`, 'success'), 0);
                });
            }

            setTimeout(() => {
                gainXp(XP_PER_DIFFICULTY[q.difficulty] || 0, q.name, q.difficulty);
                checkAchievements('COMPLETE_QUEST', { difficulty: q.difficulty });
                addNotification('QUEST CLEAR', `Mission Accomplished: ${q.name}.`, 'success');
                if (QUEST_COIN_REWARDS[q.difficulty] > 0) addNotification('REWARD GRANTED', `Received ${QUEST_COIN_REWARDS[q.difficulty]} Shop Coins.`, 'info');
            }, 0);

            return { ...prevState, quests: q.type === 'one-time' ? prevState.quests.filter(quest => quest.id !== id) : prevState.quests, completedQuests: [completionRecord, ...prevState.completedQuests], player: { ...prevState.player, shopCoins: prevState.player.shopCoins + (QUEST_COIN_REWARDS[q.difficulty] || 0), attributes: newAttributes } };
        });
    }, [addNotification, gainXp, checkAchievements]);

    const startDungeon = useCallback((id: string) => {
        const dungeon = DUNGEONS.find(d => d.id === id);
        if (dungeon) {
            setState(s => ({ ...s, activeDungeon: { id: `d-${Date.now()}`, dungeonId: id, startedAt: Date.now(), currentFloorIndex: 0, currentTaskIndex: 0, taskStatus: {} } }));
            addNotification('GATE ENTERED', `Incursion initiated: ${dungeon.name}.`, 'info');
        }
    }, [addNotification]);

    const progressDungeon = useCallback(() => {
        setState(prevState => {
            if (!prevState.activeDungeon) return prevState;
            const dungeon = DUNGEONS.find(d => d.id === prevState.activeDungeon!.dungeonId);
            if (!dungeon) return prevState;
            const currentFloor = dungeon.floors[prevState.activeDungeon.currentFloorIndex];
            const currentTask = currentFloor.tasks[prevState.activeDungeon.currentTaskIndex];
            const isLastTask = prevState.activeDungeon.currentTaskIndex >= currentFloor.tasks.length - 1;
            const newAttributes = { ...prevState.player.attributes };
            if (currentTask?.attribute) {
                const points = Math.max(1, Math.floor(STAT_POINTS_PER_DIFFICULTY[dungeon.grade] / 3));
                newAttributes[currentTask.attribute] = (newAttributes[currentTask.attribute] || 0) + points;
                setTimeout(() => addNotification('STAT INCREASE', `${currentTask.attribute?.toUpperCase()} +${points}`, 'success'), 0);
            }
            if (isLastTask) {
                if (prevState.activeDungeon.currentFloorIndex >= dungeon.floors.length - 1) return { ...prevState, player: { ...prevState.player, attributes: newAttributes }, activeDungeon: { ...prevState.activeDungeon, currentTaskIndex: currentFloor.tasks.length } };
                setTimeout(() => addNotification('FLOOR CLEARED', `Moving to floor ${prevState.activeDungeon!.currentFloorIndex + 2}...`, 'info'), 0);
                return { ...prevState, player: { ...prevState.player, attributes: newAttributes }, activeDungeon: { ...prevState.activeDungeon, currentFloorIndex: prevState.activeDungeon.currentFloorIndex + 1, currentTaskIndex: 0 } };
            }
            return { ...prevState, player: { ...prevState.player, attributes: newAttributes }, activeDungeon: { ...prevState.activeDungeon, currentTaskIndex: prevState.activeDungeon.currentTaskIndex + 1 } };
        });
    }, [addNotification]);

    const clearActiveDungeon = useCallback(() => {
        setState(prevState => {
            if (!prevState.activeDungeon) return prevState;
            const dungeon = DUNGEONS.find(d => d.id === prevState.activeDungeon!.dungeonId);
            if (!dungeon) return prevState;
            let coins = 0;
            const drops: Record<string, number> = {};
            const rand = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
            if (dungeon.grade === DifficultyEnum.E) coins = rand(3, 8);
            else if (dungeon.grade === DifficultyEnum.D) coins = rand(5, 15);
            else if (dungeon.grade === DifficultyEnum.C) { coins = rand(10, 25); drops[MATERIALS.COPPER] = rand(1, 2); drops[MATERIALS.IRON] = rand(1, 2); }
            else if (dungeon.grade === DifficultyEnum.B) { coins = rand(15, 40); drops[MATERIALS.COPPER] = rand(5, 8); drops[MATERIALS.IRON] = rand(5, 8); drops[MATERIALS.ALUMINIUM] = rand(2, 3); drops[MATERIALS.FANG] = Math.random() > 0.5 ? 1 : 0; }
            else if (dungeon.grade === DifficultyEnum.A) { coins = rand(50, 100); drops[MATERIALS.COPPER] = rand(5, 10); drops[MATERIALS.IRON] = rand(5, 10); drops[MATERIALS.ALUMINIUM] = rand(5, 8); drops[MATERIALS.FANG] = rand(1, 5); if (Math.random() > 0.7) drops[MATERIALS.DIAMOND] = rand(1, 5); if (Math.random() > 0.9) drops[MATERIALS.SHARD] = rand(1, 2); }
            else { coins = dungeon.grade === DifficultyEnum.S ? rand(200, 500) : rand(300, 750); drops[MATERIALS.COPPER] = rand(35, 80); drops[MATERIALS.IRON] = rand(35, 80); drops[MATERIALS.ALUMINIUM] = rand(30, 60); drops[MATERIALS.FANG] = rand(25, 55); drops[MATERIALS.DIAMOND] = rand(10, 25); drops[MATERIALS.SHARD] = rand(2, 5); drops[MATERIALS.BLOODSTONE] = rand(0, 3); }

            const newInventoryMaterials = [...prevState.inventory.materials];
            Object.entries(drops).forEach(([id, count]) => {
                if (count <= 0) return;
                const idx = newInventoryMaterials.findIndex(m => m.id === id);
                if (idx > -1) newInventoryMaterials[idx] = { ...newInventoryMaterials[idx], count: newInventoryMaterials[idx].count + count };
                else newInventoryMaterials.push({ id, name: id.replace('mat_', '').replace('_', ' ').toUpperCase(), count, rank: dungeon.grade });
            });

            const dropSummary = Object.entries(drops)
                .filter(([_, count]) => count > 0)
                .map(([id, count]) => `${id.replace('mat_', '').replace('_', ' ').toUpperCase()} x${count}`)
                .join(', ');

            // Trigger Reward Group notifications simultaneously
            setTimeout(() => {
                gainXp(dungeon.rewards?.xp || 0, `Cleared ${dungeon.name}`, dungeon.grade);
                checkAchievements('CLEAR_DUNGEON', { grade: dungeon.grade });
                addNotification('DUNGEON CLEAR', `${dungeon.name} extraction complete.`, 'info');
                if (dropSummary) addNotification('LOOT ACQUIRED', dropSummary, 'success');
            }, 0);

            return { ...prevState, activeDungeon: null, player: { ...prevState.player, shopCoins: prevState.player.shopCoins + coins }, dungeonHistory: [{ id: dungeon.id, name: dungeon.name, grade: dungeon.grade, completedAt: Date.now(), status: 'cleared' }, ...prevState.dungeonHistory], dungeonCooldowns: { ...prevState.dungeonCooldowns, [dungeon.id]: { date: new Date().toISOString().split('T')[0], status: 'cleared' } }, inventory: { ...prevState.inventory, materials: newInventoryMaterials } };
        });
    }, [addNotification, gainXp, checkAchievements]);

    const failActiveDungeon = useCallback(() => {
        setState(prevState => {
            if (!prevState.activeDungeon) return prevState;
            const dungeon = DUNGEONS.find(d => d.id === prevState.activeDungeon!.dungeonId);
            if (!dungeon) return prevState;
            if (dungeon.failurePenalty?.xp) setTimeout(() => gainXp(-dungeon.failurePenalty!.xp, `Failed ${dungeon.name}`, dungeon.grade), 0);
            return { ...prevState, activeDungeon: null, dungeonHistory: [{ id: dungeon.id, name: dungeon.name, grade: dungeon.grade, completedAt: Date.now(), status: 'failed' }, ...prevState.dungeonHistory], dungeonCooldowns: { ...prevState.dungeonCooldowns, [dungeon.id]: { date: new Date().toISOString().split('T')[0], status: 'failed' } } };
        });
    }, [gainXp]);

    const buyItem = useCallback((item: ShopItem) => {
        setState(s => {
            if (s.player.shopCoins >= item.cost) {
                const newState = { ...s, player: { ...s.player, shopCoins: s.player.shopCoins - item.cost }, inventory: { ...s.inventory, storage: [...s.inventory.storage, item] } };
                setTimeout(() => { addNotification('SYSTEM EXCHANGE', `${item.name} acquired.`, 'info'); checkOwnershipAchievements(newState.inventory); }, 0);
                return newState;
            }
            addNotification('INSUFFICIENT COINS', 'Access denied.', 'danger');
            return s;
        });
    }, [addNotification, checkOwnershipAchievements]);

    const enhanceGear = useCallback((gearId: string) => {
        setState(prevState => {
            let gear: ShopItem | null = null;
            let location: any = null;
            let storageIdx = prevState.inventory.storage.findIndex(i => i.id === gearId);
            if (storageIdx !== -1) { gear = { ...prevState.inventory.storage[storageIdx] }; location = 'storage'; }
            else { for (const slot in prevState.inventory.equipment) { if (prevState.inventory.equipment[slot as EquipmentSlot]?.id === gearId) { gear = { ...prevState.inventory.equipment[slot as EquipmentSlot]! }; location = slot; break; } } }
            if (!gear || (gear.enhancementLevel || 0) >= 5) return prevState;
            const reqs: any = { [DifficultyEnum.B]: [{ mat: MATERIALS.COPPER, qty: 20 }, { mat: MATERIALS.IRON, qty: 15 }], [DifficultyEnum.A]: [{ mat: MATERIALS.IRON, qty: 25 }, { mat: MATERIALS.FANG, qty: 3 }], [DifficultyEnum.S]: [{ mat: MATERIALS.SHARD, qty: 3 }], [DifficultyEnum.S_PLUS]: [{ mat: MATERIALS.BLOODSTONE, qty: 1 }, { mat: MATERIALS.IRON, qty: 5 }], [DifficultyEnum.X]: [{ mat: MATERIALS.BLOODSTONE, qty: 2 }, { mat: MATERIALS.FANG, qty: 5 }] };
            const mats = reqs[gear.rank] || [];
            if (!mats.every((r: any) => (prevState.inventory.materials.find(m => m.id === r.mat)?.count || 0) >= r.qty)) { addNotification('MATERIALS MISSING', 'Gather more resources.', 'danger'); return prevState; }
            gear.enhancementLevel = (gear.enhancementLevel || 0) + 1;
            const newInventory = { ...prevState.inventory, materials: prevState.inventory.materials.map(m => { const req = mats.find((r: any) => r.mat === m.id); return req ? { ...m, count: m.count - req.qty } : m; }) };
            if (location === 'storage') newInventory.storage[storageIdx] = gear; else newInventory.equipment[location as EquipmentSlot] = gear;
            // Progression Group: pop up simultaneously
            setTimeout(() => addNotification('ENHANCEMENT SUCCESS', `${gear!.name} upgraded to +${gear!.enhancementLevel}.`, 'info'), 0);
            return { ...prevState, inventory: newInventory };
        });
    }, [addNotification]);

    const advanceGear = useCallback((gearId: string) => {
        setState(prevState => {
            let gear: ShopItem | null = null;
            let location: any = null;
            let storageIdx = prevState.inventory.storage.findIndex(i => i.id === gearId);
            if (storageIdx !== -1) { gear = { ...prevState.inventory.storage[storageIdx] }; location = 'storage'; }
            else { for (const slot in prevState.inventory.equipment) { if (prevState.inventory.equipment[slot as EquipmentSlot]?.id === gearId) { gear = { ...prevState.inventory.equipment[slot as EquipmentSlot]! }; location = slot; break; } } }
            if (!gear || (gear.enhancementLevel || 0) < 5) return prevState;
            const costs: any = { [DifficultyEnum.B]: { coins: 200 }, [DifficultyEnum.A]: { coins: 250 }, [DifficultyEnum.S]: { coins: 450, diamond: 8 }, [DifficultyEnum.S_PLUS]: { coins: 1000, diamond: 25 }, [DifficultyEnum.X]: { coins: 1500, diamond: 15 } };
            const cost = costs[gear.rank];
            if (prevState.player.shopCoins < cost.coins || (cost.diamond && (prevState.inventory.materials.find(m => m.id === MATERIALS.DIAMOND)?.count || 0) < cost.diamond)) { addNotification('ADVANCEMENT FAILED', 'Requirements not met.', 'danger'); return prevState; }
            const currentStar = gear.stars || 0;
            const maxStars = gear.rank === DifficultyEnum.B ? 2 : gear.rank === DifficultyEnum.A ? 3 : 5;
            if (currentStar >= maxStars) return prevState;
            gear.stars = currentStar + 1;
            gear.enhancementLevel = 0;
            gear.unlockedTraits = [...(gear.unlockedTraits || []), ADVANCEMENT_TRAITS[gear.rank][currentStar]];
            const newInventory = { ...prevState.inventory, materials: prevState.inventory.materials.map(m => (cost.diamond && m.id === MATERIALS.DIAMOND) ? { ...m, count: m.count - cost.diamond! } : m) };
            if (location === 'storage') newInventory.storage[storageIdx] = gear; else newInventory.equipment[location as EquipmentSlot] = gear;
            // Progression Group: pop up simultaneously
            setTimeout(() => { addNotification('GEAR ASCENSION', `${gear!.name} star upgraded.`, 'info'); checkAchievements('ADVANCE_GEAR'); }, 0);
            return { ...prevState, player: { ...prevState.player, shopCoins: prevState.player.shopCoins - cost.coins }, inventory: newInventory };
        });
    }, [addNotification, checkAchievements]);

    const addSkill = useCallback((name: string, grade: Difficulty, stars: number, status: 'locked' | 'unlocked', category: string, description: string, guide: string, prerequisites: SkillPrerequisite[], folderId?: string) => {
        const isHighTier = [DifficultyEnum.S, DifficultyEnum.S_PLUS, DifficultyEnum.X].includes(grade);
        setState(s => ({
            ...s,
            skills: [...s.skills, {
                id: `sk-${Date.now()}`,
                name, grade, originalGrade: grade, stars, status, category, description, guide, prerequisites, folderId,
                starProgress: 0, unlockProgress: 0,
                masteryLevel: isHighTier ? 1 : 0,
                dailyTraining: { date: new Date().toISOString().split('T')[0], count: 0 }
            }]
        }));
        addNotification('SKILL LOGGED', `Ability initialized: ${name}`, 'info');
    }, [addNotification]);

    const improveSkill = useCallback((skillId: string) => {
        setState(prevState => {
            const skillIdx = prevState.skills.findIndex(s => s.id === skillId);
            if (skillIdx === -1) return prevState;
            const skills = [...prevState.skills];
            const skill = { ...skills[skillIdx] };
            const isHighTier = [DifficultyEnum.S, DifficultyEnum.S_PLUS, DifficultyEnum.X].includes(skill.originalGrade);

            // Handle Daily Cap
            const today = new Date().toISOString().split('T')[0];
            if (!skill.dailyTraining || skill.dailyTraining.date !== today) {
                skill.dailyTraining = { date: today, count: 0 };
            }

            if (skill.dailyTraining.count >= 5) {
                setTimeout(() => addNotification('CAPACITY REACHED', `Maximum daily training limit (5/5) reached for ${skill.name}.`, 'warning'), 0);
                return prevState;
            }

            if (skill.status === 'locked') {
                const req = SKILL_UNLOCK_REQUIREMENTS[skill.grade];
                skill.unlockProgress += 1;
                if (skill.unlockProgress >= req) {
                    skill.status = 'unlocked'; skill.unlockProgress = 0;
                    // Progression/Milestone Group simultaneously
                    setTimeout(() => { addNotification('SKILL UNLOCKED', `Ability synchronized: ${skill.name}`, 'info'); gainXp(XP_FOR_SKILL_UNLOCK[skill.grade], `Unlocking ${skill.name}`); }, 0);
                } else setTimeout(() => addNotification('TRAINING LOGGED', `Unlock progress: ${skill.unlockProgress}/${req}`, 'info'), 0);
            } else {
                const req = TRAINING_PER_HALF_STAR[skill.grade];
                skill.starProgress += 1;
                if (skill.starProgress >= req) {
                    skill.starProgress = 0; skill.stars += 0.5;
                    setTimeout(() => checkAchievements('TRAIN_SKILL'), 0);
                    if (skill.stars >= 5) {
                        if (isHighTier) {
                            if ((skill.masteryLevel || 0) < 4) {
                                skill.masteryLevel = (skill.masteryLevel || 0) + 1; skill.stars = 0;
                                // Progression Group: pop up simultaneously
                                setTimeout(() => { addNotification('SKILL ASCENSION', `${skill.name} Tier Up!`, 'achievement'); gainXp((XP_FOR_SKILL_ASCENSION[skill.grade] || 10) * 5, `Ascending ${skill.name}`); }, 0);
                            } else if (skill.grade === DifficultyEnum.S) {
                                skill.grade = DifficultyEnum.S_PLUS; skill.stars = 0; skill.masteryLevel = 0;
                                setTimeout(() => { addNotification('RANK PROMOTION', `${skill.name} promoted to S+!`, 'level_up'); gainXp(500, `Promoting ${skill.name}`); checkAchievements('ADVANCE_SKILL'); }, 0);
                            } else setTimeout(() => addNotification('PEAK MASTERY', `${skill.name} maxed.`, 'achievement'), 0);
                        } else {
                            const nextGradeMap: any = { [DifficultyEnum.E]: DifficultyEnum.D, [DifficultyEnum.D]: DifficultyEnum.C, [DifficultyEnum.C]: DifficultyEnum.B, [DifficultyEnum.B]: DifficultyEnum.A, [DifficultyEnum.A]: DifficultyEnum.S };
                            const next = nextGradeMap[skill.grade];
                            if (next) {
                                skill.grade = next; skill.stars = 0; skill.masteryLevel = 0;
                                setTimeout(() => { addNotification('RANK PROMOTION', `${skill.name} promoted to ${next}!`, 'level_up'); gainXp(XP_FOR_SKILL_UNLOCK[next] || 100, `Promoting ${skill.name}`); checkAchievements('ADVANCE_SKILL'); }, 0);
                            } else setTimeout(() => addNotification('PEAK MASTERY', `${skill.name} maxed at S-Rank.`, 'achievement'), 0);
                        }
                    }
                } else setTimeout(() => addNotification('TRAINING LOGGED', `${skill.name} progress: ${skill.starProgress}/${req}`, 'info'), 0);
            }

            // Increment daily count
            skill.dailyTraining.count += 1;
            skills[skillIdx] = skill;
            return { ...prevState, skills };
        });
    }, [addNotification, gainXp, checkAchievements]);

    const toggleTaskListTask = useCallback((day: DayOfWeek, id: string) => {
        setState(s => ({
            ...s,
            weeklyPlan: {
                ...s.weeklyPlan,
                [day]: s.weeklyPlan[day].map(t => t.id === id ? { ...t, completed: !t.completed } : t)
            }
        }));
    }, []);

    const addTaskListTask = useCallback((day: DayOfWeek, text: string) => {
        setState(s => ({
            ...s,
            weeklyPlan: {
                ...s.weeklyPlan,
                [day]: [...s.weeklyPlan[day], { id: `task-${Date.now()}`, text, completed: false }]
            }
        }));
    }, []);

    const deleteTaskListTask = useCallback((day: DayOfWeek, id: string) => {
        setState(s => ({
            ...s,
            weeklyPlan: {
                ...s.weeklyPlan,
                [day]: s.weeklyPlan[day].filter(t => t.id !== id)
            }
        }));
    }, []);

    const addQuest = useCallback((name: string, difficulty: Difficulty, type: 'repetitive' | 'one-time', attributes: Attribute[], description: string, rounds: number, roundDuration: number, intervalDuration: number) => {
        setState(s => ({
            ...s,
            quests: [...s.quests, {
                id: `q-${Date.now()}`,
                name, difficulty, type, attributes, description, rounds, roundDuration, intervalDuration
            }]
        }));
        addNotification('QUEST INITIALIZED', `New objective registered: ${name}`, 'info');
    }, [addNotification]);

    const deleteQuest = useCallback((id: string) => {
        setState(s => ({
            ...s,
            quests: s.quests.filter(q => q.id !== id)
        }));
    }, []);

    const failQuest = useCallback((id: string) => {
        setState(prevState => {
            const q = prevState.quests.find(x => x.id === id);
            if (!q) return prevState;
            const penaltyAmount = q.failurePenalty?.xp || (XP_PER_DIFFICULTY[q.difficulty] || 0) * 2;
            setTimeout(() => {
                gainXp(-penaltyAmount, `Failing ${q.name}`, q.difficulty);
                addNotification('MISSION FAILED', `Penalty applied for ${q.name}.`, 'danger');
            }, 0);
            return prevState;
        });
    }, [addNotification, gainXp]);

    const exportState = useCallback(() => {
        const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(state));
        const downloadAnchorNode = document.createElement('a');
        downloadAnchorNode.setAttribute("href", dataStr);
        downloadAnchorNode.setAttribute("download", `rll_backup_${new Date().toISOString().split('T')[0]}.json`);
        document.body.appendChild(downloadAnchorNode);
        downloadAnchorNode.click();
        downloadAnchorNode.remove();
        addNotification('SYSTEM BACKUP', 'State exported successfully.', 'info');
    }, [state, addNotification]);

    const importState = useCallback((json: string) => {
        try {
            const parsed = JSON.parse(json);
            if (parsed.player) {
                const questsWithSystem = [...parsed.quests];
                if (!questsWithSystem.some(q => q.id === 'sys_x_01')) {
                    questsWithSystem.push(SYSTEM_QUESTS.find(q => q.id === 'sys_x_01')!);
                }
                setState({ ...parsed, quests: questsWithSystem, notifications: [], events: [] });
                addNotification('RESTORE SUCCESS', 'System state synchronized.', 'success');
            }
        } catch (e) {
            addNotification('RESTORE FAILED', 'Data corruption detected.', 'danger');
        }
    }, [addNotification]);

    return { 
        ...state, 
        gainXp, clearActiveDungeon, enhanceGear, advanceGear, toggleTaskListTask, addTaskListTask, deleteTaskListTask, addQuest, deleteQuest, failQuest, completeQuest, startDungeon, progressDungeon, failActiveDungeon, buyItem, 
        renamePlayer: (newName: string) => { if (newName.trim()) { setState(s => ({ ...s, player: { ...s.player, name: newName.trim() } })); addNotification('IDENTITY UPDATED', `Recognized as [${newName}].`, 'info'); } }, 
        equipItem: (item: ShopItem) => setState(s => { const newStorage = s.inventory.storage.filter(i => i.id !== item.id); if (s.inventory.equipment[item.slot!]) newStorage.push(s.inventory.equipment[item.slot!]!); const newState = { ...s, inventory: { ...s.inventory, equipment: { ...s.inventory.equipment, [item.slot!]: item }, storage: newStorage } }; setTimeout(() => { addNotification('EQUIPMENT UPDATED', `${item.name} synced.`, 'info'); checkOwnershipAchievements(newState.inventory); }, 0); return newState; }), 
        unequipItem: (slot: EquipmentSlot) => setState(s => { const item = s.inventory.equipment[slot]; if (!item || Berserker_GEAR_IDS.includes(item.id)) return s; const newState = { ...s, inventory: { ...s.inventory, equipment: { ...s.inventory.equipment, [slot]: null }, storage: [...s.inventory.storage, item] } }; setTimeout(() => { addNotification('EQUIPMENT REMOVED', `${item!.name} desynced.`, 'info'); checkOwnershipAchievements(newState.inventory); }, 0); return newState; }), 
        breakGear: (slot: EquipmentSlot) => setState(s => { const orbIdx = s.inventory.storage.findIndex(i => i.id === 'brilliant_light_orb'); if (orbIdx === -1) { addNotification('ACTION IMPOSSIBLE', 'Light Orb required.', 'danger'); return s; } const newState = { ...s, inventory: { ...s.inventory, equipment: { ...s.inventory.equipment, [slot]: null }, storage: s.inventory.storage.filter((_, i) => i !== orbIdx) } }; setTimeout(() => { addNotification('CURSE BROKEN', 'Cursed gear destroyed.', 'info'); checkOwnershipAchievements(newState.inventory); }, 0); return newState; }), 
        clearEvents, addEvent, importState, exportState, addSkill, 
        deleteSkill: (id: string) => { setState(s => ({ ...s, skills: s.skills.filter(sk => sk.id !== id) })); addNotification('SKILL ERASED', 'Purged from database.', 'warning'); }, 
        addSkillFolder: (name: string, category: string, icon: string) => { setState(s => ({ ...s, skillFolders: [...s.skillFolders, { id: `sf-${Date.now()}`, name, category, icon }] })); addNotification('FOLDER INITIALIZED', `Organisation unit "${name}" established.`, 'info'); }, 
        deleteSkillFolder: (id: string) => { setState(s => ({ ...s, skillFolders: s.skillFolders.filter(f => f.id !== id) })); addNotification('FOLDER DELETED', 'Removed.', 'warning'); }, 
        addCategory: (name: string, icon: string) => { setState(s => ({ ...s, categories: [...s.categories, { name, icon }] })); addNotification('CATEGORY ESTABLISHED', `Classification "${name}" logged.`, 'info'); }, 
        deleteCategory: (name: string) => { setState(s => ({ ...s, categories: s.categories.filter(c => c.name !== name) })); addNotification('CATEGORY REMOVED', 'Purged.', 'warning'); }, 
        improveSkill 
    };
};

import React, { useState, useMemo, useRef, useLayoutEffect, useEffect } from 'react';
import type { Skill } from '../types';
import { Difficulty } from '../types';
import { TRAINING_PER_HALF_STAR, SKILL_UNLOCK_REQUIREMENTS } from '../constants';

// --- ICONS ---
const LockIcon = () => (<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 fill-gray-400" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 1a4.5 4.5 0 00-4.5 4.5V9H5a2 2 0 00-2 2v6a2 2 0 002 2h10a2 2 0 002-2v-6a2 2 0 00-2-2h-.5V5.5A4.5 4.5 0 0010 1zm3 8V5.5a3 3 0 10-6 0V9h6z" clipRule="evenodd" /></svg>);
const FullStarIcon: React.FC<{ className?: string }> = ({ className }) => (<svg className={className} viewBox="0 0 20 20"><path d="M10 15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0l2.939 5.955 6.572.955-4.756 4.635 1.123 6.545z"/></svg>);
const HalfStarIcon: React.FC<{ className?: string }> = ({ className }) => (<svg className={className} viewBox="0 0 20 20"><path d="M10 0v15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0z"/></svg>);
const EmptyStarIcon: React.FC<{ className?: string }> = ({ className }) => (<svg className={className} viewBox="0 0 20 20"><path d="M10 15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0l2.939 5.955 6.572.955-4.756 4.635 1.123 6.545z"/></svg>);
const InfoIcon = () => (<svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" /></svg>);

// --- STYLES ---
const difficultyStyles: Record<Difficulty, { text: string; border: string; shadow: string; bg: string; glowClass?: string }> = {
  [Difficulty.E]: { text: 'text-gray-300', border: 'border-gray-500/50', shadow: 'hover:shadow-gray-500/20', bg: 'bg-gray-700/20' },
  [Difficulty.D]: { text: 'text-green-300', border: 'border-green-600/50', shadow: 'hover:shadow-green-500/20', bg: 'bg-green-800/10' },
  [Difficulty.C]: { text: 'text-orange-300', border: 'border-orange-600/50', shadow: 'hover:shadow-orange-500/20', bg: 'bg-orange-800/10' },
  [Difficulty.B]: { text: 'text-indigo-300', border: 'border-indigo-600/50', shadow: 'hover:shadow-indigo-500/20', bg: 'bg-indigo-800/10' },
  [Difficulty.A]: { text: 'text-purple-300', border: 'border-purple-600/50', shadow: 'hover:shadow-purple-500/20', bg: 'bg-purple-800/10' },
  [Difficulty.S]: { text: 'text-yellow-300', border: 'border-yellow-600/50', shadow: 'hover:shadow-yellow-500/20', bg: 'bg-yellow-800/10', glowClass: 'animate-grade-s-glow' },
  [Difficulty.S_PLUS]: { text: 'text-red-300', border: 'border-transparent', shadow: '', bg: 'bg-red-800/10', glowClass: 'animate-grade-s-plus-glow' },
  [Difficulty.X]: { text: 'text-red-400', border: 'border-transparent', shadow: '', bg: 'bg-black/60', glowClass: 'animate-black-hole' },
};

// --- HELPER COMPONENTS ---
const StarRating: React.FC<{ stars: number; masteryLevel: number; showMastery: boolean }> = ({ stars, masteryLevel, showMastery }) => {
  const fullStars = Math.floor(stars);
  const hasHalfStar = stars % 1 !== 0;

  const starColors = ['fill-white', 'fill-blue-400', 'fill-purple-400', 'fill-yellow-400', 'fill-red-500'];
  const glowClasses = ['', '', '', 'animate-gold-star-glow', 'animate-red-star-glow'];

  const starColor = showMastery ? (starColors[masteryLevel] || 'fill-white') : 'fill-white';
  const glowClass = showMastery ? (glowClasses[masteryLevel] || '') : '';

  return (
    <div className="flex">
      {[...Array(5)].map((_, i) => {
        if (i < fullStars) { return <FullStarIcon key={i} className={`w-4 h-4 ${starColor} ${glowClass}`} />; }
        if (i === fullStars && hasHalfStar) { return <HalfStarIcon key={i} className={`w-4 h-4 ${starColor} ${glowClass}`} />; }
        return <EmptyStarIcon key={i} className="w-4 h-4 fill-gray-600" />;
      })}
    </div>
  );
};

// --- SKILL NODE ---
interface SkillNodeProps {
    skill: Skill;
    onImprove: (skillId: string) => void;
    onDelete: (skillId: string) => void;
    isPrereqsMet: boolean;
    prereqDetails: string;
}
const SkillNode: React.FC<SkillNodeProps> = ({ skill, onImprove, onDelete, isPrereqsMet, prereqDetails }) => {
    const styles = difficultyStyles[skill.grade];
    const masteryLevel = skill.masteryLevel || 0;
    const isHighTier = [Difficulty.S, Difficulty.S_PLUS, Difficulty.X].includes(skill.originalGrade);
    const today = new Date().toISOString().split('T')[0];
    const dailyCount = skill.dailyTraining?.date === today ? skill.dailyTraining.count : 0;
    const isDailyLimitReached = dailyCount >= 5;

    let isFullyMastered = false;
    let isReadyForAscension = false;
    let isReadyForPromotion = false;

    if (isHighTier) {
        isReadyForAscension = skill.stars === 5 && masteryLevel < 4;
        isReadyForPromotion = skill.stars === 5 && masteryLevel === 4 && skill.grade === Difficulty.S;
        isFullyMastered = skill.stars === 5 && ((masteryLevel === 4 && skill.grade === Difficulty.S_PLUS) || skill.grade === Difficulty.X);
    } else {
        isReadyForPromotion = skill.stars === 5 && skill.grade !== Difficulty.S;
        isFullyMastered = skill.stars === 5 && skill.grade === Difficulty.S;
    }

    const isDisabled = !isPrereqsMet || isFullyMastered || isDailyLimitReached;
    const nodeRef = useRef<HTMLDivElement>(null);
    const [tooltipVisible, setTooltipVisible] = useState(false);
    const [pulseAnimationClass, setPulseAnimationClass] = useState('');
    const isInitialMount = useRef(true);

    useEffect(() => {
        if (isInitialMount.current) { isInitialMount.current = false; }
        else {
            setPulseAnimationClass('animate-train-pulse');
            const pulseTimer = setTimeout(() => { setPulseAnimationClass(''); }, 700);
            return () => clearTimeout(pulseTimer);
        }
    }, [skill.starProgress, skill.unlockProgress, skill.status, skill.grade, skill.masteryLevel]);

    const nodeClasses = () => {
        if (skill.grade === Difficulty.X) return 'animate-black-hole';
        if (skill.grade === Difficulty.S_PLUS) return 'animate-grade-s-plus-glow';
        if (skill.grade === Difficulty.S) return 'animate-grade-s-glow';
        if (isHighTier && masteryLevel === 3) return 'animate-mastered-glow glowing-border';
        return `${styles.border} ${styles.shadow}`;
    };

    if (skill.status === 'locked') {
        const unlockRequirement = SKILL_UNLOCK_REQUIREMENTS[skill.grade];
        const unlockPercentage = (skill.unlockProgress / unlockRequirement) * 100;
        return (
            <div ref={nodeRef} data-skill-id={skill.id} onMouseEnter={() => !isPrereqsMet && setTooltipVisible(true)} onMouseLeave={() => setTooltipVisible(false)} className={`glass-panel group relative p-3 rounded-lg border w-64 flex-shrink-0 ${styles.bg} ${styles.border} transition-all duration-300 ${styles.shadow} ${!isPrereqsMet ? 'opacity-40 grayscale-[0.5]' : ''} ${pulseAnimationClass}`}>
                <div className="absolute top-2 right-2 flex items-center gap-1 z-20">
                    {!isPrereqsMet && <div className="text-gray-400"><InfoIcon/></div>}
                     <button onClick={(e) => { e.stopPropagation(); onDelete(skill.id); }} className="p-1 rounded-full bg-gray-900/50 text-gray-500 hover:bg-red-800/70 hover:text-red-300 opacity-0 group-hover:opacity-100 transition-opacity">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                     </button>
                </div>
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center"><div className={`font-orbitron text-lg font-bold w-9 text-center mr-2 ${styles.text} drop-shadow-md`}>[{skill.grade}]</div><div><p className="font-bold text-gray-400 text-[13px] tracking-tight">{skill.name}</p></div></div>
                    <div className="flex items-center gap-1 text-gray-500"><LockIcon /><span className="font-orbitron text-[9px] font-bold">LOCKED</span></div>
