        case DifficultyEnum.D: return { text: 'text-green-400', border: 'border-green-500/60', bg: 'bg-green-500/10', glow: '' };
        case DifficultyEnum.C: return { text: 'text-blue-400', border: 'border-blue-500/60', bg: 'bg-blue-500/10', glow: '' };
